1	type Cell = [number, number]; // [x, y]
2	
3	const toKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	function neighborsOf([x, y]: Cell): Cell[] {
6	  const neighbors: Cell[] = [];
7	  for (let dx = -1; dx <= 1; dx++) {
8	    for (let dy = -1; dy <= 1; dy++) {
9	      if (dx === 0 && dy === 0) continue;
10	      neighbors.push([x + dx, y + dy]);
11	    }
12	  }
13	  return neighbors;
14	}
15	
16	function countLiveNeighbors(cell: Cell, living: Set<string>): number {
17	  return neighborsOf(cell).filter((n) => living.has(toKey(n))).length;
18	}
19	
20	function isAliveNextGeneration(isAlive: boolean, liveNeighbors: number): boolean {
21	  return liveNeighbors === 3 || (isAlive && liveNeighbors === 2);
22	}
23	
24	function candidateCells(cells: Cell[]): Cell[] {
25	  const candidates = new Map<string, Cell>();
26	  for (const cell of cells) {
27	    candidates.set(toKey(cell), cell);
28	    for (const neighbor of neighborsOf(cell)) candidates.set(toKey(neighbor), neighbor);
29	  }
30	  return [...candidates.values()];
31	}
32	
33	export function nextGeneration(cells: Cell[]): Cell[] {
34	  const living = new Set(cells.map(toKey));
35	
36	  return candidateCells(cells).filter((cell) =>
37	    isAliveNextGeneration(living.has(toKey(cell)), countLiveNeighbors(cell, living)),
38	  );
39	}
